  { to: '/transaksi', icon: ArrowLeftRight, label: 'Transaksi' },
  { to: '/dompet', icon: Wallet, label: 'Dompet' },
  { to: '/laporan', icon: BarChart3, label: 'Laporan' },
  { to: '/goals', icon: Target, label: 'Goals' },
  { to: '/insights', icon: Sparkles, label: 'AI Insights' },
